@import '../../utils/control-inactive.css';

.surface {
  box-sizing: border-box;
  position: relative;
  border: none;
  padding: 0;
  margin: 0;
  font: inherit;
  color: inherit;
  background: none;
  text-decoration: none;
  text-align: left;
  cursor: default;
  appearance: none;
  -webkit-appearance: none;
}

/* Backgrounds */
.bg-primary    { background-color: var(--color-background-primary); }
.bg-secondary  { background-color: var(--color-background-secondary); }
.bg-transparent { background-color: transparent; }
.bg-translucent {
  background-color: var(--color-background-translucent);
  backdrop-filter: blur(var(--effect-blur-md));
  -webkit-backdrop-filter: blur(var(--effect-blur-md));
}

/* Intent × Contrast */
.intent-brand-faint      { background-color: var(--color-background-faint-brand); }
.intent-brand-medium     { background-color: var(--color-background-medium-brand); }
.intent-brand-bold       { background-color: var(--color-background-bold-brand); }
.intent-brand-strong     { background-color: var(--color-background-strong-brand); }
.intent-positive-faint   { background-color: var(--color-background-faint-positive); }
.intent-positive-medium  { background-color: var(--color-background-medium-positive); }
.intent-positive-bold    { background-color: var(--color-background-bold-positive); }
.intent-positive-strong  { background-color: var(--color-background-strong-positive); }
.intent-negative-faint   { background-color: var(--color-background-faint-negative); }
.intent-negative-medium  { background-color: var(--color-background-medium-negative); }
.intent-negative-bold    { background-color: var(--color-background-bold-negative); }
.intent-negative-strong  { background-color: var(--color-background-strong-negative); }
.intent-warning-faint    { background-color: var(--color-background-faint-warning); }
.intent-warning-medium   { background-color: var(--color-background-medium-warning); }
.intent-warning-bold     { background-color: var(--color-background-bold-warning); }
.intent-warning-strong   { background-color: var(--color-background-strong-warning); }
.intent-caution-faint    { background-color: var(--color-background-faint-caution); }
.intent-caution-medium   { background-color: var(--color-background-medium-caution); }
.intent-caution-bold     { background-color: var(--color-background-bold-caution); }
.intent-caution-strong   { background-color: var(--color-background-strong-caution); }
.intent-ai-faint         { background-color: var(--color-background-faint-ai); }
.intent-ai-medium        { background-color: var(--color-background-medium-ai); }
.intent-ai-bold          { background-color: var(--color-background-bold-ai); }
.intent-ai-strong        { background-color: var(--color-background-strong-ai); }
.intent-neutral-faint    { background-color: var(--color-background-faint-neutral); }
.intent-neutral-medium   { background-color: var(--color-background-medium-neutral); }
.intent-neutral-bold     { background-color: var(--color-background-bold-neutral); }
.intent-neutral-strong   { background-color: var(--color-background-strong-neutral); }
.intent-walkthrough-faint  { background-color: var(--color-background-faint-walkthrough); }
.intent-walkthrough-medium { background-color: var(--color-background-medium-walkthrough); }
.intent-walkthrough-bold   { background-color: var(--color-background-bold-walkthrough); }
.intent-walkthrough-strong { background-color: var(--color-background-strong-walkthrough); }
.intent-guide-faint      { background-color: var(--color-background-faint-guide); }
.intent-guide-medium     { background-color: var(--color-background-medium-guide); }
.intent-guide-bold       { background-color: var(--color-background-bold-guide); }
.intent-guide-strong     { background-color: var(--color-background-strong-guide); }

/* Elevation */
.elevation-none {}
.elevation-depressed    { box-shadow: var(--effect-elevation-depressed-sm); }
.elevation-depressed-md { box-shadow: var(--effect-elevation-depressed-md); }
.elevation-flat         { box-shadow: var(--effect-elevation-elevated-sm); }
.elevation-elevated     { box-shadow: var(--effect-elevation-elevated-md); }
.elevation-floating     { box-shadow: var(--effect-elevation-elevated-floating); }
.elevation-overlayTop    { box-shadow: var(--effect-elevation-elevated-panel-top); }
.elevation-overlayRight  { box-shadow: var(--effect-elevation-elevated-panel-right); }
.elevation-overlayBottom { box-shadow: var(--effect-elevation-elevated-panel-bottom); }
.elevation-overlayLeft   { box-shadow: var(--effect-elevation-elevated-panel-left); }

/* Edges */
.edge-top    { border-top:    var(--dimension-stroke-width-015) solid var(--color-border-tertiary); }
.edge-right  { border-right:  var(--dimension-stroke-width-015) solid var(--color-border-tertiary); }
.edge-bottom { border-bottom: var(--dimension-stroke-width-015) solid var(--color-border-tertiary); }
.edge-left   { border-left:   var(--dimension-stroke-width-015) solid var(--color-border-tertiary); }

/* Radius */
.radius-none { border-radius: var(--dimension-radius-000); }
.radius-xs   { border-radius: var(--dimension-radius-050); }
.radius-sm   { border-radius: var(--dimension-radius-075); }
.radius-md   { border-radius: var(--dimension-radius-100); }
.radius-lg   { border-radius: var(--dimension-radius-125); }
.radius-xl   { border-radius: var(--dimension-radius-175); }
.radius-2xl  { border-radius: var(--dimension-radius-200); }
.radius-full { border-radius: var(--dimension-radius-half); }

/* Interactive */
.interactive {
  cursor: pointer;
  transition: transform var(--effect-motion-short-2);
  --_hover-bg: var(--color-interaction-hover);
  --_pressed-bg: var(--color-interaction-pressed);
}
.interactive:hover   { background-color: var(--_hover-bg); }
.interactive:active  { background-color: var(--_pressed-bg); transform: scale(var(--dimension-scale-subtle)); }
.interactive:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-space-025);
}

/* Selected */
.selected::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  pointer-events: none;
  z-index: 0;
  background-color: var(--color-interaction-hover);
}
.selected > * { position: relative; z-index: 1; }

/* Inactive: `.ds-control-inactive` (25% opacity). */

import { Component, Prop, h, Host } from '@stencil/core';

export type SurfaceIntent =
  | 'brand' | 'positive' | 'negative' | 'warning' | 'caution'
  | 'ai' | 'neutral' | 'walkthrough' | 'guide';
export type SurfaceBackground = 'primary' | 'secondary' | 'transparent' | 'translucent';
export type SurfaceContrast = 'faint' | 'medium' | 'bold' | 'strong';
export type SurfaceElevation =
  | 'none' | 'depressed' | 'depressed-md' | 'flat' | 'elevated' | 'floating'
  | 'overlayTop' | 'overlayRight' | 'overlayBottom' | 'overlayLeft';
export type SurfaceEdge = 'top' | 'right' | 'bottom' | 'left';
export type SurfaceRadius = 'none' | 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl' | 'full' | (string & {});
export type SurfaceElement = 'div' | 'section' | 'aside' | 'article' | 'header' | 'footer' | 'main' | 'nav' | 'span';

const RADIUS_PRESETS = new Set(['none', 'xs', 'sm', 'md', 'lg', 'xl', '2xl', 'full']);

@Component({
  tag: 'ds-surface',
  styleUrl: 'Surface.css',
  scoped: true,
})
export class Surface {
  @Prop() background: SurfaceBackground = 'transparent';
  @Prop() intent: SurfaceIntent | undefined;
  @Prop() contrast: SurfaceContrast = 'faint';
  @Prop() elevation: SurfaceElevation = 'none';
  /** Space-separated list of edges: "top bottom" etc. Only applies when elevation='none'. */
  @Prop() edge: string | undefined;
  @Prop() radius: SurfaceRadius | undefined;
  @Prop() interactive: boolean = false;
  @Prop() selected: boolean = false;
  @Prop() isInactive: boolean = false;
  @Prop() as: SurfaceElement = 'div';

  render() {
    // Polymorphic element: TSX treats a variable tag as a component, so a
    // dynamic intrinsic element name must be cast to `any` to render.
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const Tag = this.as as any;

    const intentClass = this.intent
      ? `intent-${this.intent}-${this.contrast}`
      : `bg-${this.background}`;

    const elevClass = `elevation-${this.elevation}`;

    const edgeClasses = this.edge && this.elevation === 'none'
      ? this.edge.trim().split(/\s+/).map(e => `edge-${e}`)
      : [];

    const radiusClass = this.radius && RADIUS_PRESETS.has(this.radius)
      ? `radius-${this.radius}`
      : '';

    const customRadius = this.radius && !RADIUS_PRESETS.has(this.radius)
      ? this.radius
      : undefined;

    const cls = [
      'surface',
      intentClass,
      elevClass,
      ...edgeClasses,
      radiusClass,
      this.interactive ? 'interactive' : '',
      this.selected ? 'selected' : '',
      this.isInactive ? 'ds-control-inactive' : '',
    ].filter(Boolean).join(' ');

    return (
      <Host style={{ display: 'contents' }}>
        <Tag
          class={cls}
          style={customRadius ? { borderRadius: customRadius } : undefined}
        >
          <slot />
        </Tag>
      </Host>
    );
  }
}
